function logRequestMethodAndUrl(req: Request, res: Response, next: NextFunction) {
  const method = req.method;
  const url = req.originalUrl || req.url;

  console.log(`${method} request to ${url}`);

  next(); // Continue with the middleware chain
}

export function setupLoggingMiddleware(app: Express.Application) {
  app.use((req: Request, res: Response, next: NextFunction) => logRequestMethodAndUrl(req, res, next));
}

