export module Utilities {
  /** Truncates the given string to a maximum length without breaking words */
  export function truncate(str: string, max: number): string {
    if (max < str.length) {
      const endIndex = Math.min(str.length, max);
      let lastSpaceIndex = str.lastIndexOf(' ', endIndex - 1);

      // Truncate at the last space before max length if possible
      return lastSpaceIndex !== -1 ? str.substring(0, lastSpaceIndex) + '...' : str.substring(0, endIndex);
    } else {
      return str;
    }
  }

  /** Converts a string to a URL-friendly slug */
  export function slugify(str: string): string {
    const lowercased = str.toLowerCase();
    let result = '';

    for (let i = 0; i < lowercased.length; i++) {
      const char = lowercased[i];

      // Remove non-alphanumeric characters except '-' and '_'
      if ((char >= 'a' && char <= 'z') || (char >= '0' && char <= '9') || (char === '-' || char === '_')) {
        result += char;
      } else {
        // Replace spaces with hyphens
        i--;
        while (i < lowercased.length - 1 && lowercased[i] === ' ') {
          lowercased = lowercased.substring(0, i) + '-' + lowercased.substring(i + 1);
        }
      }
    }

    return result;
  }
}

