export type StringOrNumber = string | number;

/**
 * Truncates a given string to the specified maximum length.
 * @param {string} str - The original string.
 * @param {number} max - The maximum allowed length of the truncated string.
 * @returns {string} The truncated string, appending an ellipsis if it was truncated.
 */
export function truncate(str: string, max: number): string {
  return str.length > max ? `${str.substring(0, max)}...` : str;
}

/**
 * Generates a URL-friendly slug from the given string.
 * @param {string} str - The original string to be slugified.
 * @returns {string} A slugified version of the input string.
 */
export function slugify(str: string): string {
  return str.toLowerCase().replace(/[^a-z0-9]/gi, '-').trim();
}

