    statusCode: number;
    message: string;
};

// Express middleware function to handle errors as JSON responses
const errorHandlerMiddleware = (): (req: Request, res: Response, next: NextFunction) => {
    return (req: Request, res: Response, next: NextFunction) => {
        // Wrap the request handler with a try-catch block
        try {
            next();
        } catch (error) {
            // Create an error response object
            const errorResponse: ErrorResponse = {
                statusCode: 500, // Default to HTTP 500 Internal Server Error
                message: 'An unexpected error occurred'
            };

            // Configure the JSON payload based on error details if available
            if (error.response) {
                errorResponse.statusCode = error.response.status;
                errorResponse.message = error.response.message || 'An unknown error occurred';
            } else {
                errorResponse.statusCode = 500; // No response details, use generic server error message
            }

            // Send the JSON error response
            res.status(errorResponse.statusCode).json(errorResponse);
        }
    };
};

// Use the middleware in your Express application setup
const app = express();
app.use(errorHandlerMiddleware());

