import { Request, Response } from 'express';

// Define the interface for our custom error object
interface CustomErrorResponse {
  status: number;
  message: string;
}

/**
 * Express middleware to handle errors and return a JSON response with status and message.
 */
function errorHandlerMiddleware(app: Express.Application): void {
  app.use((err: Error, req: Request, res: Response, next): void => {
    // Check if the error is an instance of the custom error object
    if (err instanceof CustomErrorResponse) {
      // Return a JSON response with status and message from the custom error object
      return res.status(err.status).json({
        status: err.status,
        message: err.message
      });
    }

    // For other types of errors, set a generic 500 internal server error response
    console.error(err);
    res.status(500).json({
      status: 500,
      message: 'Internal Server Error'
    });
  });
}

